import{j as e,M as w,m as M,r as b}from"./index-zT0FZdz8.js";import{m as E}from"./matriz-black-Cu8EiTUZ.js";import{A as j}from"./arrow-up-right-QnQq6F_r.js";import{C as h}from"./check-BxkqGPP9.js";import{S as A}from"./shield-check-DmfCY6k2.js";import{C as S}from"./chevron-down-6vR9yCZj.js";const u="https://pay.hotmart.com/B73928367P?off=h0n7diwh&checkoutMode=10",C="https://www.youtube.com/embed/sVLzrUURJaw",O={escrevendo:{slug:"escrevendo",path:"/ppto-escrevendo",eyebrow:"✍️ Para autores que ainda estão escrevendo",h1:"O erro que faz muitos livros fracassarem começa bem antes da publicação.",sub:"Enquanto você escreve, está tomando decisões que podem aproximar seu livro dos leitores — ou afastá-lo deles antes mesmo do lançamento. Se a estratégia só entra depois, o livro pode nascer desalinhado, difícil de posicionar e muito mais difícil de vender.",cta:"QUERO CONSTRUIR MEU LIVRO DO JEITO CERTO",videoText:"Assista ao vídeo e entenda por que a estratégia de um livro começa antes de ele ficar pronto.",dor:{tag:"A dor do tempo perdido",h2:"Muitos autores só descobrem tarde demais que escrever bem não basta.",body:"Eles passam meses, às vezes anos, escrevendo com dedicação. Mas deixam para pensar no leitor, no posicionamento, na comunicação e na estratégia só depois que o livro está pronto. O problema é que, quando isso acontece, muitas decisões importantes já foram tomadas. E algumas delas tornam o livro mais difícil de vender."},entrada:{h2:"Um livro não nasce estratégico no lançamento. Ele começa a ser construído muito antes.",body:"A maioria dos autores tenta resolver o problema tarde demais. Só pensa em divulgação quando o livro já está pronto. Só pensa no leitor quando precisa vender. Só pensa no mercado quando chega a hora de publicar. Mas um livro forte não nasce de uma peça isolada. Ele nasce do alinhamento entre obra, autor, leitor, mercado e fundamentos editoriais. É isso que a Matriz do Autor Estratégico mostra. ↓"},pos:{h2:"Sem método, o livro pode até ser finalizado. Mas isso não significa que ele vai funcionar no mercado.",body:"É por isso que tantos autores escrevem com dedicação, terminam seus originais… e só depois descobrem que construíram algo difícil de posicionar, divulgar e sustentar. O problema não é só escrever. É escrever um livro que já nasce com direção, clareza e potencial real de circulação — quando essa estrutura existe desde o começo, o lançamento deixa de depender de improviso.",beneficios:["Gerar interesse real quando for lançado","Ser mais fácil de comunicar","Alcançar o leitor certo com mais clareza","Começar sua trajetória com muito mais força"],transicao:"O MTBB existe para evitar esse erro desde a origem. Para que seu livro não apenas fique pronto, mas seja construído para ser lido, desejado e sustentado no mercado."},custo:{icon:"⏱️",title:"O custo de adiar enquanto você escreve",body:"Cada semana escrevendo sem método é uma semana de retrabalho garantido. O livro que você está escrevendo agora vai ter um lançamento — com ou sem sistema. A diferença é só quanto retrabalho vem antes."},checklist:["Está escrevendo seu livro agora","Quer evitar erros que só aparecem depois da publicação","Quer entender melhor o leitor antes de finalizar a obra","Quer chegar ao lançamento com mais clareza","Não quer deixar a divulgação para a última hora","Quer transformar escrita em uma trajetória real de autor"],depoimentos:["Léo Dicker","Giuliana & Susana","Robson Leite","Marcio Scavone"],depoimentosH2:"Autores que aprenderam o método enquanto escreviam",ctaFinal:{h2:"O futuro do seu livro começa antes da última página.",body:"Se você quer escrever com mais direção, construir uma obra mais estratégica e chegar ao lançamento com muito mais clareza, o MTBB é o próximo passo.",button:"QUERO CONSTRUIR MEU LIVRO COM ESTRATÉGIA"},precoIntro:"Você ainda está escrevendo. É o melhor momento — cada aula que você assistir pode mudar o que você escreve amanhã."},lancando:{slug:"lancando",path:"/ppto-lancando",eyebrow:"🚀 Para autores prestes a publicar",h1:"Você escreveu. Agora o que acontece a seguir pode aproximar seu livro dos leitores… ou do esquecimento.",sub:"O lançamento do seu livro não decide só as vendas da primeira semana. Ele pode definir se o seu livro será lido, desejado e recomendado — ou se vai perder força logo depois de publicado.",cta:"QUERO LANÇAR MEU LIVRO COM ESTRATÉGIA",videoText:"Assista ao vídeo e entenda o que separa lançamentos que ganham força de lançamentos que desaparecem cedo.",dor:{tag:"O ciclo curto demais",h2:"Para a maioria dos autores, o ciclo de vida de um livro termina rápido demais.",body:"O autor publica, vende alguns exemplares, movimenta amigos, seguidores e conhecidos… E depois o livro esfria. Não porque ele necessariamente é ruim. Mas porque foi publicado sem a estrutura necessária para gerar desejo, circulação e recomendação.",erros:["Achar que publicar é o mesmo que lançar","Começar a pensar em marketing tarde demais","Divulgar sem posicionamento claro","Esperar que o livro se venda sozinho","Confundir esforço com estratégia","Depender apenas de amigos e seguidores"]},entrada:{h2:"Lançar um livro não é só colocar uma obra no mundo.",body:"É colocar obra, autor, leitor e mercado para funcionarem juntos. Quando uma dessas peças falha, o lançamento até pode acontecer. Mas o livro não ganha força. E quando o autor tenta compensar isso com mais posts, mais ansiedade e mais improviso, ele só acelera um resultado que não se sustenta. É por isso que a Matriz do Autor Estratégico é tão importante. ↓"},pos:{h2:"Um livro pode até vender no início. Mas, sem sistema, ele perde força rápido.",body:"É por isso que tantos autores vivem o mesmo ciclo: publicam, vendem um pouco, movimentam amigos e seguidores… e depois veem o livro esfriar. O problema nunca foi só lançar — é lançar de um jeito que faça o livro continuar vivo nas semanas seguintes, sendo lido, recomendado e comprado ao longo do tempo.",beneficios:["Mais leitura real","Mais recomendação e boca a boca","Mais permanência no mercado","Mais autoridade para o autor"],transicao:"O MTBB foi criado exatamente para isso. Não apenas para ajudar você a publicar. Mas para fazer o seu lançamento virar o início de uma trajetória mais forte."},custo:{icon:"⏱️",title:"A janela que não volta",body:"O lançamento acontece uma vez. Os próximos 30 dias depois da publicação são a única janela em que imprensa retorna, livraria aceita estoque e algoritmo amplia. Essa janela não volta."},checklist:["Está com o livro prestes a publicar","Quer lançar com mais estratégia","Quer gerar desejo antes e depois do lançamento","Quer evitar que o livro esfrie logo após a publicação","Não quer depender apenas de amigos, seguidores ou sorte","Quer construir uma base de leitores reais e ser reconhecido como autor"],depoimentos:["Candice Pascoal","Tonia Casarin","Mauricio Benvenutti","Dr. Arnoni Caldart"],depoimentosH2:"Autores que lançaram com o método e chegaram às listas",ctaFinal:{h2:"Seu livro merece ser lido. E não apenas lançado.",body:"Se você quer publicar com mais estratégia, gerar desejo e construir um livro que continue vivo no mercado, o MTBB é o próximo passo.",button:"QUERO LANÇAR COM ESTRATÉGIA"},precoIntro:"Você está prestes a lançar. Cada semana sem o sistema é uma semana de vendas e autoridade que não voltam."},reativando:{slug:"reativando",path:"/ppto-reativando",eyebrow:"🔄 Para autores que já publicaram",h1:"Seu livro já foi lançado. Mas ele ainda não ganhou o espaço, a circulação e a força que merecia.",sub:"Talvez ele tenha vendido no começo. Talvez nem isso. Mas se hoje ele está distante das pessoas, fora das conversas e sem ganhar tração, o problema não é necessariamente a obra. É a falta de uma estratégia capaz de manter esse livro vivo no mercado.",cta:"QUERO REATIVAR MEU LIVRO",videoText:"Assista ao vídeo e entenda por que alguns livros continuam circulando — e outros param cedo demais.",dor:{tag:"O silêncio depois do lançamento",h2:"O mais frustrante não é só vender pouco. É ver o livro parar.",body:"Você publicou. Fez o possível com o que sabia. Talvez tenha divulgado, falado com amigos, postado, tentado movimentar o livro. Mas, com o tempo, ele perdeu força. Parou de circular. Parou de ser comentado. Parou de crescer. E isso não significa que o livro não tenha valor. Significa que faltou estrutura para mantê-lo vivo.",erros:["Acreditar que depois da publicação não há mais o que fazer","Depender apenas do impulso inicial","Divulgar sem reposicionamento","Não entender por que o livro travou","Tentar reativar sem estratégia","Confundir insistência com direção"]},entrada:{h2:"Quando um livro não cresce depois de publicado, o problema quase nunca está em uma única coisa.",body:"Não é só capa. Não é só rede social. Não é só algoritmo. Não é só preço. Um livro volta a ganhar força quando obra, autor, leitor, mercado e fundamentos editoriais começam a funcionar juntos. É exatamente isso que a Matriz do Autor Estratégico revela. ↓"},pos:{h2:"O problema não é só que o seu livro vendeu pouco. É que ele começou a desaparecer.",body:"Sem leitores falando, recomendando e comprando, um livro vai perdendo presença, relevância e espaço no mercado. E é exatamente isso que acontece com muitos autores: lançam, fazem algum movimento, tentam divulgar… mas nunca constroem a base necessária para manter o livro vivo.",beneficios:["Mais circulação","Mais relevância","Mais constância nas vendas","Mais reconhecimento para você como autor"],transicao:"O MTBB existe para tirar o seu livro desse ciclo de estagnação. Não só para gerar um pico. Mas para reconstruir a estrutura que faz ele voltar a ser visto, lembrado e recomendado."},custo:{icon:"⏱️",title:"O custo de cada mês parado",body:"Cada mês que o livro fica parado, ele sai de mais conversas. O custo da estagnação não é zero — é perda contínua de relevância."},checklist:["Já publicou seu livro","Sente que ele não ganhou a tração que merecia","Quer entender por que ele parou","Quer reativar a circulação da obra","Quer voltar a gerar interesse e recomendação","Não quer depender apenas de posts soltos"],depoimentos:["Simone Simon","André Siqueira","Jorge Azevedo","Marcelo Apovian"],depoimentosH2:"Autores que reativaram — e não pararam mais",ctaFinal:{h2:"Seu livro não precisava ter parado assim.",body:"Se você quer reativar sua obra, voltar a gerar interesse e construir uma estratégia para que seu livro seja visto, lembrado e recomendado, o MTBB é o próximo passo.",button:"QUERO REATIVAR MEU LIVRO"},precoIntro:"Seu livro tem histórico de vendas e leitores reais. Isso é o maior ativo que existe — o método só precisa reativá-lo."}},k={"Léo Dicker":{resultado:"Adotado",sub:"por escolas + lançado no exterior",quote:"Você não precisa ser um escritor nato para ter um livro de sucesso. O que você precisa é conhecimento, vontade, bons parceiros e a estratégia certa.",name:"Léo Dicker",role:"Empresário de tecnologia"},"Giuliana & Susana":{resultado:"Nº 1",sub:"Publishnews — Negócios",quote:"Giuliana e Susana transformaram metodologia em livro Nº 1 em Negócios no Publishnews — com destaque em Estadão e Valor Econômico.",name:"Giuliana & Susana",role:"Especialistas em Marca Pessoal"},"Robson Leite":{resultado:"Autoridade",sub:"acadêmica e de mercado",quote:"Investir no método valeu cada centavo. Me tornei autoridade em gestão pública no mercado e no meio acadêmico.",name:"Robson Leite",role:"Professor e Mestre em Adm. Pública"},"Marcio Scavone":{resultado:"Academia",sub:"Paulista de Letras",quote:"A Dany detecta, desenvolve e direciona para o lugar merecido a força particular de cada autor. É um dom.",name:"Marcio Scavone",role:"Escritor, fotógrafo, membro da APL"},"Candice Pascoal":{resultado:"50.000",sub:"cópias vendidas",quote:"A Dany não só me ajudou a transformar meu sonho em realidade — guiou a estratégia e execução. Meu livro se tornou o 1º best-seller de uma mulher empreendedora no Brasil.",name:"Candice Pascoal",role:"Fundadora da Kickante"},"Tonia Casarin":{resultado:"Nº 1",sub:"na Amazon",quote:"Meu maior desafio era que o público do livro era muito específico. Com a estratégia certa, superei as expectativas na pré-venda e alcancei o Nº 1 na Amazon.",name:"Tonia Casarin",role:"Especialista em Liderança"},"Mauricio Benvenutti":{resultado:"3",sub:"best-sellers consecutivos",quote:"Depois de 3 best-sellers, posso afirmar: a campanha de lançamento é o que separa um livro comum de um best-seller. A Dany foi essencial nos meus três.",name:"Mauricio Benvenutti",role:"Co-fundador StartSe"},"Dr. Arnoni Caldart":{resultado:"Veja",sub:"Amazon · Publishnews",quote:"As orientações são excelentes. Sem dúvida, o Método The Book Business foi essencial — entrei para as 3 listas mais importantes do Brasil.",name:"Dr. Arnoni Caldart",role:"Médico"},"Simone Simon":{resultado:"Long-seller",sub:"vendas estáveis por anos",quote:"A Dany foi essencial. Transformamos o livro em best-seller e, depois, em long-seller. Ela é uma fonte inesgotável de conhecimento sobre o mercado editorial.",name:"Simone Simon",role:"Negociação e Gestão"},"André Siqueira":{resultado:"Forbes",sub:"Under 30 · co-fundador RD Station",quote:"Saber trabalhar a ponte entre o mercado editorial tradicional e as novas oportunidades do mundo digital é um talento que a Dany exerce com maestria.",name:"André Siqueira",role:"Co-fundador RD Station"},"Jorge Azevedo":{resultado:"Escala",sub:"empresa + palestras + livro",quote:"Com décadas de experiência, já lancei vários livros e trato cada um como um empreendimento. O método estruturou o que eu fazia intuitivamente — e os resultados escalaram.",name:"Jorge Azevedo",role:"Consultor, empresário e investidor-anjo"},"Marcelo Apovian":{resultado:"Topo",sub:"rankings nacionais",quote:"Após conquistar uma editora tradicional, Lelo conquistou o topo dos principais rankings do Brasil — e alavancou empresa e palestras ao mesmo tempo.",name:"Marcelo Apovian",role:"Ex-atleta Olímpico e Empresário"}},d="'Space Grotesk', system-ui, sans-serif",v